The typical pattern is a root stack with an `App` screen that holds the tab navigator:

```tsx
// navigation/RootStack.tsx
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { createBottomTabNavigator } from '@react-navigation/bottom-tabs';

const Tab = createBottomTabNavigator();
function Tabs() {
  return (
    <Tab.Navigator>
      <Tab.Screen name="Home" component={HomeScreen} />
      <Tab.Screen name="Profile" component={ProfileScreen} />
    </Tab.Navigator>
  );
}

const Stack = createNativeStackNavigator();
export function RootStack() {
  return (
    <Stack.Navigator>
      <Stack.Screen name="App" component={Tabs} options={{ headerShown: false }} />
      <Stack.Screen name="Detail" component={DetailScreen} />
    </Stack.Navigator>
  );
}
```

`headerShown: false` on the `App` screen hides the stack header so only the tab bar shows. Full-screen modals (`presentation: 'modal'`) still appear above the tab bar.

Use the `useNavigation` hook with the root stack's `navigate` method. Because the tab screen is nested inside the root stack, it has access to the parent navigator:

```tsx
import { useNavigation } from '@react-navigation/native';
import type { NativeStackNavigationProp } from '@react-navigation/native-stack';

type RootStackParams = {
  App: undefined;
  Detail: { itemId: string };
};

function HomeScreen() {
  const nav = useNavigation<NativeStackNavigationProp<RootStackParams>>();
  return (
    <Button
      title="Open Detail"
      onPress={() => nav.navigate('Detail', { itemId: '42' })}
    />
  );
}
```

React Navigation automatically bubbles the `navigate` call up to the nearest navigator that can handle `'Detail'`.
